import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import "./CompanyPendingBugs.css";

export default function CompanyPendingBugs() {
  const [bugs, setBugs] = useState([]);
  const token = localStorage.getItem("token");
  const navigate = useNavigate();

  /* ======================
     FETCH PENDING BUGS
  ====================== */

  const fetchPendingBugs = async () => {
    try {
      const res = await fetch(
        "http://localhost:5000/api/bugs/company/bugs",
        {
          headers: { Authorization: `Bearer ${token}` },
        }
      );

      const data = await res.json();

      const pending = (data.bugs || []).filter(
        (bug) => bug.status === "submitted"
      );

      setBugs(pending);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    fetchPendingBugs();
  }, [token]);

  /* ======================
     UPDATE STATUS
  ====================== */

  const updateStatus = async (id, status) => {
    try {
      let body = { status };

      /* ===== DUPLICATE ===== */
      if (status === "duplicate") {
        const originalId = prompt("Enter Original Bug ID:");

        if (!originalId) {
          alert("Original Bug ID is required!");
          return;
        }

        body.duplicateOf = originalId;
      }

      /* ===== APPROVE ===== */
      if (status === "approved") {
        const severity = prompt(
          "Enter severity (low / medium / high / critical):"
        );

        if (!["low", "medium", "high", "critical"].includes(severity)) {
          alert("Invalid severity");
          return;
        }

        const reward = prompt("Enter reward amount:");

        if (!reward || Number(reward) <= 0) {
          alert("Reward must be greater than 0");
          return;
        }

        body.severity = severity;
        body.reward = Number(reward);
      }

      const res = await fetch(
        `http://localhost:5000/api/bugs/validate/${id}`,
        {
          method: "PATCH",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${token}`,
          },
          body: JSON.stringify(body),
        }
      );

      const data = await res.json();

      if (!res.ok) {
        alert(data.msg || "Failed to update bug");
        return;
      }

      fetchPendingBugs();

    } catch (err) {
      console.error(err);
    }
  };

  return (
    <div className="company-page">

      {/* TOP BAR */}
      <div className="top-bar">
        <button
          className="back-btn"
          onClick={() => navigate("/company")}
        >
          ⬅ Back to Dashboard
        </button>

        <h1>🐞 Pending Bugs</h1>
      </div>

      {/* BUG LIST */}
      {bugs.length === 0 ? (
        <p className="muted">No new bugs 🎉</p>
      ) : (
        <div className="bug-grid">
          {bugs.map((bug) => (
            <div className="bug-card" key={bug._id}>
              <h3>{bug.title}</h3>

              <div className="bug-id">
                ID: {bug._id}
              </div>

              <p className="description">
                {bug.description}
              </p>

              <div className="actions">
                <button
                  className="approve"
                  onClick={() => updateStatus(bug._id, "approved")}
                >
                  ✔ Approve
                </button>

                <button
                  className="reject"
                  onClick={() => updateStatus(bug._id, "rejected")}
                >
                  ✖ Reject
                </button>

                <button
                  className="duplicate"
                  onClick={() => updateStatus(bug._id, "duplicate")}
                >
                  ⚠ Duplicate
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
